// Load applicant profile from file based on profile_id
const fs = require('fs');
const appRecord = $input.first().json;
const profilePaths = (process.env.APPLICANT_PROFILE_PATHS || '').split(',').map(p => p.trim()).filter(Boolean);

let profile = null;
for (const p of profilePaths) {
  const candidate = JSON.parse(fs.readFileSync(p, 'utf8'));
  if (candidate.profile_id === appRecord.profile_id) {
    profile = candidate;
    break;
  }
}

if (!profile) {
  return [{ json: {
    error: true,
    reason: `profile_not_found: ${appRecord.profile_id}`,
    application_id: appRecord.application_id
  }}];
}

// Select resume variant based on role family
const resumeVariant = profile.resume_variants[appRecord.role_family] || profile.resume_variants.default;

return [{ json: { ...appRecord, profile, resume_variant: resumeVariant } }];

// Parse browser agent output.
// The browser_agent.js script outputs a JSON result to stdout.
// Expected shape:
// { status: 'draft_complete'|'needs_user_input'|'error', checkpoint: {}, novel_questions: [], error: '' }

const rawOutput = $input.first().json.stdout || '{}';
const appId = $('Build Fill Plan').first().json.application_id;

let result;
try {
  result = JSON.parse(rawOutput);
} catch {
  result = { status: 'error', error: 'browser_agent_output_not_json', checkpoint: {}, novel_questions: [] };
}

const draftStatus = result.status === 'draft_complete' ? 'draft_complete'
  : result.status === 'needs_user_input' ? 'needs_user_input'
  : 'error';

return [{ json: {
  application_id: appId,
  draft_status: draftStatus,
  form_checkpoint: JSON.stringify(result.checkpoint || {}),
  novel_questions: JSON.stringify(result.novel_questions || []),
  last_error: result.error || null
} }];
